## TCP Tests

### Basic Connection

```rust
#[tokio::test] // or use our runtime
async fn test_tcp_connect_accept() {
    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();

    let connect_task = TcpStream::connect(addr);
    let accept_task = listener.accept();

    let (client, (server, _addr)) = join!(connect_task, accept_task);
    let client = client.unwrap();
    let server = server.0;

    // Both connected
    assert!(client.peer_addr().is_ok());
    assert!(server.peer_addr().is_ok());
}
```

### Echo Test

```rust
#[test]
async fn test_tcp_echo() {
    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();

    // Echo server
    let server = cx.spawn(async move {
        let (mut stream, _) = listener.accept().await.unwrap();
        let mut buf = [0u8; 1024];
        loop {
            let n = stream.read(&mut buf).await.unwrap();
            if n == 0 { break; }
            stream.write_all(&buf[..n]).await.unwrap();
        }
    });

    // Client
    let mut client = TcpStream::connect(addr).await.unwrap();
    client.write_all(b"hello world").await.unwrap();

    let mut buf = vec![0u8; 11];
    client.read_exact(&mut buf).await.unwrap();
    assert_eq!(&buf, b"hello world");
}
```

### Large Transfer

```rust
#[test]
async fn test_tcp_large_transfer() {
    // Transfer 10MB of data
    let data: Vec<u8> = (0..10_000_000).map(|i| i as u8).collect();

    // ... setup server and client ...

    // Send all data
    client.write_all(&data).await.unwrap();
    client.shutdown().await.unwrap();

    // Receive all data
    let mut received = Vec::new();
    server.read_to_end(&mut received).await.unwrap();

    assert_eq!(data, received);
}
```

### Connection Refused

```rust
#[test]
async fn test_tcp_connection_refused() {
    // Connect to port nothing is listening on
    let result = TcpStream::connect("127.0.0.1:1").await;
    assert!(result.is_err());
    assert_eq!(result.unwrap_err().kind(), io::ErrorKind::ConnectionRefused);
}
```

### Multiple Accepts

```rust
#[test]
async fn test_tcp_multiple_accepts() {
    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();

    let clients: Vec<_> = (0..10)
        .map(|_| TcpStream::connect(addr))
        .collect();

    let servers = async {
        let mut streams = Vec::new();
        for _ in 0..10 {
            let (stream, _) = listener.accept().await.unwrap();
            streams.push(stream);
        }
        streams
    };

    let (clients, servers) = join!(
        futures::future::join_all(clients),
        servers,
    );

    assert_eq!(clients.iter().filter(|r| r.is_ok()).count(), 10);
    assert_eq!(servers.len(), 10);
}
```

## UDP Tests

### Basic Send/Receive

```rust
#[test]
async fn test_udp_send_recv() {
    let server = UdpSocket::bind("127.0.0.1:0").await.unwrap();
    let server_addr = server.local_addr().unwrap();

    let client = UdpSocket::bind("127.0.0.1:0").await.unwrap();

    // Send
    client.send_to(b"hello", &server_addr).await.unwrap();

    // Receive
    let mut buf = [0u8; 10];
    let (n, addr) = server.recv_from(&mut buf).await.unwrap();

    assert_eq!(&buf[..n], b"hello");
    assert_eq!(addr, client.local_addr().unwrap());
}
```

### Connected UDP

```rust
#[test]
async fn test_udp_connected() {
    let a = UdpSocket::bind("127.0.0.1:0").await.unwrap();
    let b = UdpSocket::bind("127.0.0.1:0").await.unwrap();

    a.connect(b.local_addr().unwrap()).await.unwrap();
    b.connect(a.local_addr().unwrap()).await.unwrap();

    a.send(b"ping").await.unwrap();

    let mut buf = [0u8; 10];
    let n = b.recv(&mut buf).await.unwrap();
    assert_eq!(&buf[..n], b"ping");
}
```

