## Unit Tests

### Checkpoint API Tests
```rust
#[cfg(test)]
mod checkpoint_tests {
    #[test]
    fn checkpoint_resets_progress_timer() {
        init_deadline_test_logging();

        let lab = LabRuntimeBuilder::new().rng_seed(42).build();

        lab.run_with_cx(|cx| async move {
            let budget = Budget::deadline(Duration::from_secs(10))
                .with_checkpoint_interval(Duration::from_millis(100));

            cx.with_budget(budget, async {
                for i in 0..5 {
                    // Each checkpoint resets the interval
                    cx.checkpoint();
                    sleep(Duration::from_millis(50)).await;
                    tracing::debug!(iteration = %i, "Checkpoint issued");
                }
            }).await;

            tracing::info!("All checkpoints issued without warning");
        });
    }

    #[test]
    fn checkpoint_with_message_recorded() {
        init_deadline_test_logging();

        let lab = LabRuntimeBuilder::new().rng_seed(42).build();

        lab.run_with_cx(|cx| async move {
            cx.checkpoint_with("Processing batch 1 of 10");

            let last_checkpoint = cx.last_checkpoint_message();
            assert_eq!(last_checkpoint, Some("Processing batch 1 of 10"));

            tracing::info!(message = ?last_checkpoint, "Checkpoint message recorded");
        });
    }
}
```

### Warning Trigger Tests
```rust
#[cfg(test)]
mod warning_tests {
    #[test]
    fn warning_triggered_at_threshold() {
        init_deadline_test_logging();

        let warnings = Arc::new(Mutex::new(Vec::new()));
        let warnings2 = warnings.clone();

        let monitor = DeadlineMonitor {
            warning_threshold: Duration::from_millis(100),
            on_warning: Box::new(move |w| {
                warnings2.lock().unwrap().push(w);
            }),
        };

        let lab = LabRuntimeBuilder::new()
            .rng_seed(42)
            .deadline_monitor(monitor)
            .build();

        lab.run_with_cx(|cx| async move {
            let budget = Budget::deadline(Duration::from_secs(1));

            cx.with_budget(budget, async {
                // No checkpoints - should trigger warning after 100ms
                sleep(Duration::from_millis(150)).await;
            }).await;
        });

        let warnings = warnings.lock().unwrap();
        assert!(!warnings.is_empty(), "Should have triggered warning");

        tracing::info!(warning_count = %warnings.len(), "Warnings triggered correctly");
    }

    #[test]
    fn warning_includes_last_checkpoint() {
        init_deadline_test_logging();

        let warnings = Arc::new(Mutex::new(Vec::new()));
        let warnings2 = warnings.clone();

        let monitor = DeadlineMonitor {
            warning_threshold: Duration::from_millis(100),
            on_warning: Box::new(move |w| {
                warnings2.lock().unwrap().push(w);
            }),
        };

        let lab = LabRuntimeBuilder::new()
            .rng_seed(42)
            .deadline_monitor(monitor)
            .build();

        lab.run_with_cx(|cx| async move {
            let budget = Budget::deadline(Duration::from_secs(1));

            cx.with_budget(budget, async {
                cx.checkpoint_with("Started processing");

                // Long pause without checkpoint
                sleep(Duration::from_millis(150)).await;
            }).await;
        });

        let warnings = warnings.lock().unwrap();
        assert!(warnings[0].last_checkpoint_message == Some("Started processing".to_string()));

        tracing::info!("Warning includes last checkpoint message");
    }
}
```

## E2E Tests

### Stuck Task Detection Workflow
```rust
#[test]
fn e2e_stuck_task_detection() {
    init_deadline_test_logging();

    tracing::info!("═══════════════════════════════════════════");
    tracing::info!("E2E: Stuck Task Detection Workflow");
    tracing::info!("═══════════════════════════════════════════");

    let detected_stuck = Arc::new(AtomicBool::new(false));
    let detected_stuck2 = detected_stuck.clone();

    let monitor = DeadlineMonitor {
        warning_threshold: Duration::from_millis(50),
        on_warning: Box::new(move |warning| {
            tracing::warn!(
                task_id = ?warning.task_id,
                remaining = ?warning.remaining,
                last_checkpoint = ?warning.last_checkpoint_message,
                "⚠️  DEADLINE WARNING: Task appears stuck!"
            );
            detected_stuck2.store(true, Ordering::SeqCst);
        }),
    };

    let lab = LabRuntimeBuilder::new()
        .rng_seed(42)
        .deadline_monitor(monitor)
        .build();

    lab.run_with_cx(|cx| async move {
        let budget = Budget::deadline(Duration::from_secs(1))
            .with_checkpoint_interval(Duration::from_millis(50));

        let _ = cx.with_budget(budget, async {
            // Simulate a task that gets stuck
            cx.checkpoint_with("Starting batch processing");

            // This simulates an I/O operation that hangs
            tracing::debug!("Simulating stuck I/O...");
            sleep(Duration::from_millis(200)).await;

        }).await;
    });

    assert!(detected_stuck.load(Ordering::SeqCst), "Should have detected stuck task");
    tracing::info!("E2E stuck task detection completed");
}
```

